on_write:
let res = #{ action: "Allow" };
if !payload.contains("attributes") {
    res.action = "Reject";
    res.reason = "Multivalued databases require an attributes array";
}
res

on_read:
let res = #{ payload: payload };
if payload.attributes.contains(query_key) {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
